code = """import json, re, pandas as pd

# Load funding data
with open('file_storage/functions.query_db:6.json', 'r') as f:
    funding = json.load(f)

# Load civic documents
with open('file_storage/functions.query_db:10.json', 'r') as f:
    docs = json.load(f)

# Create funding DataFrame
funding_df = pd.DataFrame(funding)
funding_df['Amount'] = pd.to_numeric(funding_df['Amount'])

# Find all unique project names mentioned in civic documents that have Spring 2022 dates
spring_2022_project_names = set()

for doc in docs:
    text = doc['text']
    lines = text.split('\n')
    
    for i in range(len(lines)):
        line = lines[i].strip()
        
        # Check for Spring 2022 in schedule lines
        if '2022' in line and ('Spring' in line or 'spring' in line):
            # Look backwards for project name
            for j in range(i-1, max(i-5, -1), -1):
                prev_line = lines[j].strip()
                if prev_line and not prev_line.isupper() and len(prev_line) > 10:
                    # This might be a project name
                    if not any(skip in prev_line for skip in ['Page', 'Agenda Item', 'To:', 'Prepared by:', 'Subject:', 'RECOMMENDED ACTION:', 'DISCUSSION:']):
                        spring_2022_project_names.add(prev_line)
                        break

# Now we have all potential project names
# Check which ones have funding data
funded_spring_projects = []
for proj_name in spring_2022_project_names:
    # Direct match
    matches = funding_df[funding_df['Project_Name'] == proj_name]
    if not matches.empty:
        for _, row in matches.iterrows():
            funded_spring_projects.append({
                'Project_Name': proj_name,
                'Funding_Amount': row['Amount'],
                'Funding_Source': row['Funding_Source']
            })
    else:
        # Try partial matching for projects with suffixes
        base_name = re.sub(r'\s+\([^)]*\)$', '', proj_name)  # Remove suffixes like (FEMA Project)
        matches = funding_df[funding_df['Project_Name'].str.contains(base_name, case=False, na=False)]
        if not matches.empty:
            for _, row in matches.iterrows():
                funded_spring_projects.append({
                    'Project_Name': proj_name,
                    'Funding_Amount': row['Amount'],
                    'Funding_Source': row['Funding_Source']
                })

# Calculate totals
spring_projects_df = pd.DataFrame(funded_spring_projects)
total_funding = int(spring_projects_df['Funding_Amount'].sum()) if not spring_projects_df.empty else 0
num_projects = len(spring_projects_df)

print('__RESULT__:')
print(json.dumps({
    'num_spring_2022_projects': num_projects,
    'total_funding': total_funding,
    'sample_projects': spring_projects_df.head(10).to_dict('records') if not spring_projects_df.empty else []
}))"""

